# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorRef, ActorSystem, Props}

// Message protocol
sealed trait BankMessage
case class Deposit(amount: BigDecimal, replyTo: Option[ActorRef] = None) extends BankMessage
case class Withdraw(amount: BigDecimal, replyTo: Option[ActorRef] = None) extends BankMessage
case object GetBalance extends BankMessage
case class BalanceResponse(balance: BigDecimal)
case class TransactionSuccess(message: String, newBalance: BigDecimal)
case class TransactionFailure(message: String, currentBalance: BigDecimal)

// Account Actor - Akka actors process messages one at a time from their mailbox,
// so `var balance` is safely accessed without explicit synchronization.
// The actor model provides inherent thread-safety through message-passing concurrency.
class AccountActor(accountId: String, initialBalance: BigDecimal = BigDecimal(0)) extends Actor {

  // This var is safe because Akka guarantees that only one message
  // is processed at a time per actor instance (the "actor confinement" guarantee).
  // No external thread can access this variable directly.
  private var balance: BigDecimal = initialBalance

  override def receive: Receive = {
    case Deposit(amount, _) =>
      if (amount <= 0) {
        sender() ! TransactionFailure(
          s"Account $accountId: Deposit amount must be positive, got $amount",
          balance
        )
      } else {
        balance += amount
        sender() ! TransactionSuccess(
          s"Account $accountId: Deposited $amount",
          balance
        )
      }

    case Withdraw(amount, _) =>
      if (amount <= 0) {
        sender() ! TransactionFailure(
          s"Account $accountId: Withdrawal amount must be positive, got $amount",
          balance
        )
      } else if (amount > balance) {
        sender() ! TransactionFailure(
          s"Account $accountId: Insufficient funds. Requested $amount but balance is $balance",
          balance
        )
      } else {
        balance -= amount
        sender() ! TransactionSuccess(
          s"Account $accountId: Withdrew $amount",
          balance
        )
      }

    case GetBalance =>
      sender() ! BalanceResponse(balance)
  }
}

object AccountActor {
  def props(accountId: String, initialBalance: BigDecimal = BigDecimal(0)): Props =
    Props(new AccountActor(accountId, initialBalance))
}

// Bank actor that manages multiple account actors
class BankActor extends Actor {
  import scala.collection.mutable

  private val accounts: mutable.Map[String, ActorRef] = mutable.Map.empty

  override def receive: Receive = {
    case CreateAccount(accountId, initialBalance) =>
      if (accounts.contains(accountId)) {
        sender() ! TransactionFailure(s"Account $accountId already exists", initialBalance)
      } else {
        val accountRef = context.actorOf(AccountActor.props(accountId, initialBalance), s"account-$accountId")
        accounts(accountId) = accountRef
        sender() ! TransactionSuccess(s"Account $accountId created", initialBalance)
      }

    case AccountMessage(accountId, message) =>
      accounts.get(accountId) match {
        case Some(accountRef) => accountRef.forward(message)
        case None => sender() ! TransactionFailure(s"Account $accountId not found", BigDecimal(0))
      }
  }
}

case class CreateAccount(accountId: String, initialBalance: BigDecimal = BigDecimal(0))
case class AccountMessage(accountId: String, message: BankMessage)

object BankActor {
  def props: Props = Props(new BankActor)
}

// Demo application
object FinancialSystemApp extends App {
  import akka.pattern.ask
  import akka.util.Timeout
  import scala.concurrent.duration._
  import scala.concurrent.{Await, Future}

  implicit val system: ActorSystem = ActorSystem("FinancialSystem")
  implicit val timeout: Timeout = Timeout(5.seconds)
  import system.dispatcher

  val bank = system.actorOf(BankActor.props, "bank")

  // Create accounts
  val setup = for {
    r1 <- (bank ? CreateAccount("ACC-001", BigDecimal(1000))).mapTo[TransactionSuccess]
    r2 <- (bank ? CreateAccount("ACC-002", BigDecimal(500))).mapTo[TransactionSuccess]
  } yield {
    println(r1)
    println(r2)
  }

  Await.result(setup, 5.seconds)

  // Simulate concurrent transactions
  val transactions: Seq[Future[Any]] = (1 to 10).map { i =>
    if (i % 3 == 0) {
      bank ? AccountMessage("ACC-001", Withdraw(BigDecimal(50)))
    } else {
      bank ? AccountMessage("ACC-001", Deposit(BigDecimal(100)))
    }
  }

  val results = Future.sequence(transactions)
  val finalResults = Await.result(results, 10.seconds)
  finalResults.foreach(println)

  // Check final balance
  val finalBalance = Await.result(
    (bank ? AccountMessage("ACC-001", GetBalance)).mapTo[BalanceResponse],
    5.seconds
  )
  println(s"Final balance for ACC-001: ${finalBalance.balance}")

  system.terminate()
}